  "versionNotice": "⚠️ Use typeVersion: 2.1 when creating this node",
  "requiredProperties": [],
  "commonProperties": [
    {
      "name": "httpMethod",
      "displayName": "HTTP Method",
      "type": "options",
      "description": "The HTTP method to listen to",
      "required": false,
      "default": "GET",
      "options": [
        {
          "value": "DELETE",
          "label": "DELETE"
        },
        {
          "value": "GET",
          "label": "GET"
        },
        {
          "value": "HEAD",
          "label": "HEAD"
        },
        {
          "value": "PATCH",
          "label": "PATCH"
        },
        {
          "value": "POST",
          "label": "POST"
        },
        {
          "value": "PUT",
          "label": "PUT"
        }
