      "name": "path",
      "displayName": "Path",
      "type": "string",
      "description": "The path to listen to, dynamic values could be specified by using ':', e.g. 'your-path/:dynamic-value'. If dynamic values are set 'webhookId' would be prepended to path.",
      "required": false,
      "default": ""
    },
    {
      "name": "responseMode",
      "displayName": "Respond",
      "type": "options",
      "description": "When and how to respond to the webhook",
      "required": false,
      "default": "onReceived",
      "options": [
        {
          "value": "onReceived",
          "label": "Immediately"
        },
        {
          "value": "lastNode",
          "label": "When Last Node Finishes"
        },
        {
          "value": "responseNode",
          "label": "Using 'Respond to Webhook' Node"
        }
      ],
      "showWhen": {
        "@version": [
          1,
          1.1,
          2
        ]
      }
    },
    {
      "name": "responseData",
      "displayName": "Response Data",
      "type": "options",
      "description": "What data should be returned. If it should return all items as an array or only the first item as object.",
      "required": false,
      "default": "firstEntryJson",
      "options": [
        {
          "value": "allEntries",
          "label": "All Entries"
        },
        {
          "value": "firstEntryJson",
          "label": "First Entry JSON"
        },
        {
          "value": "firstEntryBinary",
          "label": "First Entry Binary"
        },
        {
          "value": "noData",
          "label": "No Response Body"
        }
      ],
      "showWhen": {
        "responseMode": [
          "lastNode"
        ]
      }
    },
    {
      "name": "responseCode",
      "displayName": "Response Code",
      "type": "number",
      "description": "The HTTP Response code to return",
      "required": false,
      "default": 200,
      "showWhen": {
        "@version": [
          1,
          1.1
        ]
      }
    }
  ],
  "operations": [],
  "metadata": {
    "totalProperties": 14,
    "isAITool": false,
    "isTrigger": true,
    "isWebhook": true,
