parameters.jsCode:
const item = $input.first();
const rawText = item.json.text || item.json.output || item.json.response || '';

try {
  const cleaned = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const parsed = JSON.parse(cleaned);

  return [{
    json: {
      prompt_final: typeof parsed.prompt_final === 'string' ? parsed.prompt_final : '',
      variables: Array.isArray(parsed.variables) ? parsed.variables : [],
      questions: Array.isArray(parsed.questions) ? parsed.questions : [],
      checklist_prereqs: Array.isArray(parsed.checklist_prereqs) ? parsed.checklist_prereqs : [],
      acceptance_tests: Array.isArray(parsed.acceptance_tests) ? parsed.acceptance_tests : [],
      meta: {
        version: 'v1',
        timestamp: new Date().toISOString()
      }
    }
  }];
} catch (parseError) {
  return [{
    json: {
      prompt_final: rawText,
      variables: [],
      questions: [],
      checklist_prereqs: [],
      acceptance_tests: [],
      meta: {
        version: 'v1',
        timestamp: new Date().toISOString(),
        warning: 'LLM output could not be parsed as JSON: ' + parseError.message
      }
    }
  }];
}

