parameters.jsCode:
const raw = $input.first().json ?? {};
const body = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

const objective = String(body.objective ?? '').trim();
const input_prompt = String(body.input_prompt ?? '').trim();
const context = String(body.context ?? '').trim();
const constraints = Array.isArray(body.constraints) ? body.constraints : [];
const output_format = String(body.output_format ?? 'markdown').trim();

const errors = [];
if (!objective) errors.push('objective is required');
if (!input_prompt) errors.push('input_prompt is required');

const is_valid = errors.length === 0;

return [{
  json: {
    is_valid,
    errors,
    body: {
      objective,
      input_prompt,
      context,
      constraints,
      output_format
    }
  }
}];

const body = $json.body;
const now = new Date().toISOString();

const schemaSample = JSON.stringify({
  prompt_final: '<complete optimized prompt — fully written, no placeholders>',
  variables: [{ name: 'string', description: 'string', required: true }],
  questions: [],
  checklist_prereqs: ['string'],
  acceptance_tests: ['Test: Given [specific input], expect [specific output]'],
  meta: {
    version: 'DEV__PromptOptimizer__v1',
    timestamp: now
  }
}, null, 2);

const systemMessage = `You are a Prompt Engineering expert specialized in designing production-grade prompts.

STRICT RULES:
1. Output MUST be valid JSON only — no markdown, no code blocks, no explanations
2. The questions field MUST always be an empty array []
3. No placeholders anywhere — no template variables like {{X}}, no [INSERT...] patterns
4. prompt_final must be complete and ready-to-use — directly optimize the given input_prompt
5. All keys in the required schema must be present with correct types
6. Do not add any keys beyond the required schema
7. Return ONLY the JSON object — starting with { and ending with }

Required output schema:
${schemaSample}`;

const userPayload = JSON.stringify({
  objective: body.objective,
  input_prompt: body.input_prompt,
  context: body.context || '',
  constraints: body.constraints || [],
  output_format: body.output_format || 'markdown',
  required_output_schema: {
    prompt_final: 'string — complete, ready-to-use, no placeholders',
    variables: [{ name: 'string', description: 'string', required: true }],
    questions: [],
    checklist_prereqs: ['string'],
    acceptance_tests: ['string'],
    meta: {
      version: 'DEV__PromptOptimizer__v1',
      timestamp: now
    }
  }
}, null, 2);

return [{
  json: {
    systemMessage,
    userPayload,
    body
  }
}];

const item = $input.first();
const rawText = item.json.text || item.json.output || item.json.response || '';

let parsed;
try {
  const cleaned = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('500: LLM output is not valid JSON — ' + e.message);
}

if (!parsed.prompt_final || typeof parsed.prompt_final !== 'string') {
  throw new Error('500: prompt_final is empty or missing in LLM response');
}

return [{
  json: {
    prompt_final: parsed.prompt_final,
    variables: Array.isArray(parsed.variables) ? parsed.variables : [],
    questions: [],
    checklist_prereqs: Array.isArray(parsed.checklist_prereqs) ? parsed.checklist_prereqs : [],
    acceptance_tests: Array.isArray(parsed.acceptance_tests) ? parsed.acceptance_tests : [],
    meta: {
      version: 'DEV__PromptOptimizer__v1',
      timestamp: (parsed.meta && parsed.meta.timestamp) ? parsed.meta.timestamp : new Date().toISOString()
    }
  }
}];

