            "jsCode": "const item = $input.first().json;\nconst { objective, input_prompt, context, constraints, output_format } = item;\nconst ph = '{' + '{';\nconst phc = '}' + '}';\nconst ct = Array.isArray(constraints) && constraints.length > 0 ? constraints.map(c => '- ' + c).join('\\n') : '- None specified.';\nconst prompt = [\n'You are an expert in prompt engineering and AI architecture.',\n'Transform the user need below into a structured, complete, reusable prompt for an LLM.',\n'',\n'## USER INPUT',\n'Objective: ' + objective,\n'Raw prompt: ' + input_prompt,\n'Context: ' + (context || 'None'),\n'Constraints:\\n' + ct,\n'Output format: ' + (output_format || 'markdown'),\n'',\n'---',\n'## INSTRUCTIONS',\n'Return ONLY valid JSON (no markdown, no backticks, no text before/after).',\n'Required structure:',\n'{',\n'  \"prompt_final\": \"# Title\\\\n\\\\n## 1. Role\\\\n[role]\\\\n\\\\n## 2. Objective\\\\n[goal]\\\\n\\\\n## 3. Context\\\\n[context]\\\\n\\\\n## 4. Inputs\\\\n[inputs with ' + ph + 'VAR' + phc + ' for dynamic values]\\\\n\\\\n## 5. Constraints\\\\n[constraints]\\\\n\\\\n## 6. Output Format\\\\n[format with example]\\\\n\\\\n## 7. Validation Checklist\\\\n[ ] Criterion\\\\n\\\\n## 8. Quick Tests\\\\n1. Test\\\\n\\\\n## 9. Do / Dont\\\\nDo: practice\\\\nDont: pitfall\",',\n'  \"variables\": [{\"name\": \"VAR\", \"description\": \"Description and example\", \"required\": true}],',\n'  \"questions\": [],',\n'  \"checklist_prereqs\": [\"Prerequisite before use\"],',\n'  \"acceptance_tests\": [\"Acceptance test description\"],',\n'  \"meta\": {\"version\": \"DEV__PromptOptimizer__v1\", \"timestamp\": \"ISO string\"}',\n'}',\n'',\n'STRICT RULES:',\n'1. questions MUST always be [] — never populate it',\n'2. prompt_final must be complete and ready-to-use — directly integrate the input_prompt content',\n'3. All sections fully written — no placeholder text in prose',\n'4. variables[] must list all ' + ph + 'VAR' + phc + ' tokens used in prompt_final',\n'5. meta.version MUST be \"DEV__PromptOptimizer__v1\"',\n'6. Output ONLY the JSON — no extra text, no markdown wrapper'\n].join('\\n');\nreturn [{ json: { ...item, llm_prompt: prompt } }];"
