parameters.jsCode:
// Build LLM Prompt — outputs { system, user } for structured chat
var item = $input.first().json;
var objective = String(item.objective ?? '').trim();
var input_prompt = String(item.input_prompt ?? '').trim();

var systemMsg = [
  "You are a prompt optimization engine.",
  "Return ONLY valid JSON. No markdown outside JSON. No explanations.",
  "Do NOT ask questions. questions must be an empty array [].",
  "Your job: transform the raw prompt into a final prompt that is directly usable (copy/paste).",
  "Do NOT output generic templates unless the raw prompt truly requires it.",
  "Keep the final prompt concise and action-oriented.",
  "Preserve the language of the raw prompt (if French, output French).",
  "Required JSON structure: { prompt_final, variables, questions, checklist_prereqs, acceptance_tests, meta }"
].join("\n");

var userMsg = JSON.stringify({
  objective: objective,
  input_prompt: input_prompt,
  output_contract: {
    prompt_final: "A single, ready-to-use optimized prompt (string).",
    variables: "List only if strictly needed; otherwise []",
    questions: [],
    checklist_prereqs: ["Optional, short"],
    acceptance_tests: ["Optional, short"]
  },
  hard_rules: [
    "questions MUST be []",
    "Avoid meta sections unless necessary",
    "prompt_final must be the optimized prompt itself, not a description"
  ]
});

return [{ json: { system: systemMsg, user: userMsg } }];

